wire [127:0] seed;
wire [127:0] entropy128;
wire [63:0] entropy64;
wire [31:0] entropy32;
wire [15:0] entropy16;
wire entropy128_valid;
wire entropy64_valid;
wire entropy32_valid;
wire entropy16_valid;
wire [63:0] rand_num;
wire rand_num_valid;
wire [3:0] cs_state;

//assign value from local signals to ports
assign seed = seed_i;
assign load = load_i;

assign poly128 = poly128_i;
assign poly64 = poly64_i;
assign poly32 = poly32_i;
assign poly16 = poly16_i;

assign rand_num_o = rand_num;
assign rand_num_valid_o = rand_num_valid;


assign seed128_o = seed128;
assign seed64_o = seed64;
assign seed32_o = seed32;
assign seed16_o = seed16;

assign rand_seg128_o = rand_seg128;
assign rand_seg64_o = rand_seg64;
assign rand_seg32_o = rand_seg32;
assign rand_seg16_o = rand_seg16;

assign cs_state_o = cs_state;

reg [1:0] seed_ct;

always @ (posedge clk)
begin
	if (!rst_n)
	begin
		seed_ct <= 2'b0;
	end
	else
	begin
		seed_ct <= seed_ct + 1;
	end
end


always @(*)
begin
	seed128 = seed;
	case(seed_ct)
		0:begin
			seed16 <= seed[127:112];
			seed32 <= seed[127:96];
			seed64 <= seed[127:64];
		end
		1:begin
			seed16 <= seed[111:96];
			seed32 <= seed[111:80];
			seed64 <= seed[111:48];
		end
		2:begin
			seed16 <= seed[95:80];
			seed32 <= seed[95:64];
			seed64 <= seed[95:32];
		end
		3:begin
			seed16 <= seed[79:64];
			seed32 <= seed[79:48];
			seed64 <= seed[79:16];
		end
		default:begin
			seed16 <= 0;
			seed32 <= 0;
			seed64 <= 0;
		end
	endcase // seed_ct
end


